func:
// 🔹 prepareTableauProprietes
// Lit la variable sélectionnée dans flow context (flow.get("varSelected"))
// et prépare msg.payload.variable attendu par le ui-template tableau.

// commentaire: structure attendue : msg.payload.variable { nomVarG, abbrVarG, descriptionVarG, dateUpdateVarG, instances[], proprietes[] }

let varSelected = flow.get("varSelected") || null;
let enrichedVars = global.get("enrichedVars","file") || {};
let variable = enrichedVars[varSelected] || null;

if (!varSelected || !variable) {
    msg.payload = { variable: { nomVarG: "", abbrVarG: "", descriptionVarG: "", dateUpdateVarG: "", instances: [], proprietes: [] } };
    msg.info = "⚠️ Aucune variable sélectionnée ou variable introuvable.";
    return msg;
}

// Construire la structure propre des propriétés (norme interne)
msg.payload = { variable: {
    nomVarG: variable.nomVarG,
    abbrVarG: variable.abbrVarG,
    descriptionVarG: variable.descriptionVarG,
    dateUpdateVarG: variable.dateUpdateVarG,
    instances: variable.instances || ["*"],
    proprietes: (variable.proprietes || []).map(p => ({
        nomP: p.nomP,
        abbrP: p.abbrP,
        typeP: p.typeP,
        schema: p.schema || null,
        valeurs: p.valeurs || {}
    }))
}};
msg.info = `✅ Variable sélectionnée : ${varSelected}`;
return msg;

// Centralise les actions envoyées par le tableau
// Stocke la propriete sélectionnée dans flow context (propSelected)
// et renvoie un msg.payload:{action, propriete}
let varSelected = flow.get("varSelected") || null;
if (msg.topic === 'propriete_action' && msg.payload) {
    let action = msg.payload.action;
    let prop = msg.payload.propriete || {};
    // sauvegarde dans flow pour que tous les éditeurs pointent la même propriété
    flow.set('propSelected', prop);
    node.status({fill:'blue',shape:'dot',text:`action: ${action} prop:${prop.nomP || ''}`});
    msg.info = `✅ Var : ${varSelected} `;
    msg.payload = { action, propriete: prop };
    return msg;
}
return null;

// 🔹 suppression de propriété
// msg.payload.propriete contient la propriété à supprimer
// on supprime de enrichedVars[varSelected].proprietes

let varSelected = flow.get('varSelected');
let enrichedVars = global.get('enrichedVars','file') || {};
let prop = msg.payload.propriete || {};
if (!varSelected || !prop || !prop.nomP) {
    msg.info = '❌ Données insuffisantes pour supprimer.';
    return msg;
}

let variable = enrichedVars[varSelected] || {};
let proprietes = variable.proprietes || [];
let idx = proprietes.findIndex(p => p.nomP === prop.nomP);
if (idx === -1) {
    msg.info = '⚠️ Propriété introuvable.';
    return msg;
}

// suppression
proprietes.splice(idx,1);
enrichedVars[varSelected].proprietes = proprietes;
global.set('enrichedVars', enrichedVars, 'file');

msg.info = `✅ Propriété "${prop.nomP}" supprimée.`;
// renvoyer vers préparation tableau pour refresh
return { payload: null, info: msg.info };

// 🔹 Prepa Formulaire Base Propriété
// Récupère la propriété déjà sauvegardée dans flow.propSelected
// Si propSelected absent, on prépare un formulaire vide (création nouvelle prop)

let prop = flow.get('propSelected') || {};
let varSelected = flow.get('varSelected');
let enrichedVars = global.get('enrichedVars','file') || {};
let variable = enrichedVars[varSelected] || {};

// si pas de property, préparer formulaire vide (création)
let payload = {
    nomP: prop.nomP || "",
    abbrP: prop.abbrP || "",
    typeP: prop.typeP || "string",
    schema: prop.schema ? JSON.stringify(prop.schema, null, 2) : "",
    instances: variable.instances || ["*"]
};

msg.payload = payload;
msg.info = `✏️ Chargement formulaire propriété: ${payload.nomP || '(nouvelle)'} `;
return msg;

// 🔹 sauvegardePropriete
// Reçoit msg.payload { nomP, abbrP, typeP, schema }
// Met à jour global.enrichedVars[varSelected].proprietes

let form = msg.payload;
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
if (!form || !varSelected) { msg.info='❌ Données incomplètes'; return msg }

let variable = enriched[varSelected] = enriched[varSelected] || { proprietes: [], instances: ['*'] };
let proprietes = variable.proprietes || [];
let propSel = flow.get('propSelected') || {};
let idx = proprietes.findIndex(p => p.nomP === (propSel.nomP || ''));

// parser schema déjà fait côté template: form.schema est null ou objet
let schemaParsed = form.schema || null;

if (idx >= 0) {
    // met à jour
    proprietes[idx].nomP = form.nomP;
    proprietes[idx].abbrP = form.abbrP;
    proprietes[idx].typeP = form.typeP;
    proprietes[idx].schema = schemaParsed;
} else {
    // ajout d'une nouvelle propriété (valeurs initialisées avec valeur par défaut pour l'instance '*')
    let newProp = { nomP: form.nomP, abbrP: form.abbrP, typeP: form.typeP, schema: schemaParsed, valeurs: {} };
    // initialiser valeurs pour chaque instance
    (variable.instances || ['*']).forEach(inst => { newProp.valeurs[inst] = null });
    proprietes.push(newProp);
    idx = proprietes.length - 1;
}

// sauvegarde
enriched[varSelected].proprietes = proprietes;
global.set('enrichedVars', enriched, 'file');

// met à jour flow.propSelected
flow.set('propSelected', proprietes[idx]);

msg.info = `✅ Propriété "${form.nomP}" sauvegardée.`;
return { payload: null, info: msg.info };

// 🔹 prepaFormSchema
// Récupère la propriété dans flow.propSelected et prépare un payload.sousProprietes[]
let prop = flow.get('propSelected') || {};
if (!prop || !prop.nomP) { msg.info='⚠️ Aucune propriété sélectionnée.'; return null }
if (prop.typeP !== 'object' && prop.typeP !== 'array') { msg.info='⚠️ Propriété non composite (object/array requis).'; return null }

let sous = [];
if (prop.schema && Array.isArray(prop.schema)) {
    sous = prop.schema.map(sp => ({ nom: sp.nomSsP, type: sp.typeSsP }));
}

msg.payload = { nomPropriete: prop.nomP, typePropriete: prop.typeP, sousProprietes: sous };
msg.info = `📐 Édition schéma: ${prop.nomP}`;
return msg;

// 🔹 sauvegarderSchema
// Reçoit msg.payload { nomPropriete, typePropriete, sousProprietes }
// Convertit en tableau schema[{nomSsP,typeSsP}] et enregistre

let form = msg.payload;
let varSelected = flow.get('varSelected');
let propSelected = flow.get('propSelected') || {};
let enriched = global.get('enrichedVars','file') || {};
if (!form || !varSelected || !propSelected) { msg.info='❌ Données incomplètes'; return msg }

let variable = enriched[varSelected] || {};
let proprietes = variable.proprietes || [];
let idx = proprietes.findIndex(p=> p.nomP === propSelected.nomP);
if (idx === -1) { msg.info='❌ Propriété introuvable'; return msg }

// construire schema à partir de sousProprietes
let newSchema = (form.sousProprietes || []).filter(sp=>sp.nom).map(sp => ({ nomSsP: sp.nom, typeSsP: sp.type }));
proprietes[idx].schema = newSchema;
// sauvegarde
enriched[varSelected].proprietes = proprietes;
global.set('enrichedVars', enriched, 'file');
// update flow.propSelected
flow.set('propSelected', proprietes[idx]);
msg.info = `✅ Schéma mis à jour pour ${propSelected.nomP}`;
return { payload: null, info: msg.info };

// 🔹 prepaFormValues
// Prépare l'éditeur de valeurs selon le type de la propriété
// si type simple -> valeursInstances: [{instance, valeur, type}]
// si object/array -> vérifie schema puis construit valeursComplexes [{instance, nomSsP, typeSsP, valeur}]

let prop = flow.get('propSelected') || {};
let varSelected = flow.get('varSelected');
let enriched = global.get('enrichedVars','file') || {};
let variable = enriched[varSelected] || {};
let instances = variable.instances || ['*'];

if (!prop || !prop.nomP) { msg.info='⚠️ Aucune propriété sélectionnée.'; return null }

if (prop.typeP === 'object' || prop.typeP === 'array') {
    // besoin d'un schema
    if (!prop.schema || !Array.isArray(prop.schema) || prop.schema.length === 0) {
        msg.info = '⚠️ Définir d\'abord le schéma pour éditer les valeurs.';
        return msg; // renvoyer msg.info pour affichage
    }
    // construire valeursComplexes
    let valeursComplexes = [];
    instances.forEach(inst => {
        // la valeur brute pour cette instance est un objet ou tableau
        let raw = (prop.valeurs && prop.valeurs[inst]) || (prop.typeP==='array'?[]:{});
        // si array on attend un array d'objets? ici on mappe par sous-propriété
        prop.schema.forEach(sp => {
            // pour object/array on supporte stockage en objet par clef nomSsP
            let v = null;
            if (prop.typeP === 'array') {
                // principe simplifié: si valeur est array of primitives, on stocke la liste joinée
                // mais pour édition par sous propriété, on essaie de récupérer un objet si possible
                // si raw est array and elements are primitives, on keep raw
                v = raw ? raw[sp.nomSsP] : null;
            } else {
                v = raw ? raw[sp.nomSsP] : null;
            }
            valeursComplexes.push({ instance: inst, nomSsP: sp.nomSsP, typeSsP: sp.typeSsP, valeur: v });
        });
    });
    msg.payload = { nomPropriete: prop.nomP, typePropriete: prop.typeP, schema: prop.schema, valeursComplexes };
    msg.info = `🧩 Édition valeurs (complexe) pour ${prop.nomP}`;
    return msg;
} else {
    // type simple
    let valeurs = prop.valeurs || {};
    let valeursInstances = instances.map(inst => ({ instance: inst, valeur: (valeurs[inst] !== undefined ? valeurs[inst] : null), type: prop.typeP }));
    msg.payload = { nomPropriete: prop.nomP, typePropriete: prop.typeP, valeursInstances };
    msg.info = `✏️ Édition valeurs (simple) pour ${prop.nomP}`;
    return msg;
}

// 🔹 sauvegarderValeurs
// Reçoit payload soit {valeursInstances[]} (simple) soit {valeursComplexes[], schema}

let form = msg.payload;
let varSelected = flow.get('varSelected');
let propSelected = flow.get('propSelected') || {};
let enriched = global.get('enrichedVars','file') || {};
if (!form || !varSelected || !propSelected) { msg.info='❌ Données incomplètes'; return msg }

let variable = enriched[varSelected] || {};
let proprietes = variable.proprietes || [];
let idx = proprietes.findIndex(p=>p.nomP === propSelected.nomP);
if (idx === -1) { msg.info='❌ Propriété introuvable'; return msg }

let prop = proprietes[idx];

if (form.valeursInstances) {
    // simple
    let valeurs = {};
    form.valeursInstances.forEach(vi => { valeurs[vi.instance] = vi.valeur });
    prop.valeurs = valeurs;
} else if (form.valeursComplexes) {
    // reconstruire par instance
    let valeurs = {};
    form.valeursComplexes.forEach(vc => {
        if (!valeurs[vc.instance]) valeurs[vc.instance] = {};
        valeurs[vc.instance][vc.nomSsP] = vc.valeur;
    });
    prop.valeurs = valeurs;
}

// sauvegarde
enriched[varSelected].proprietes = proprietes;
global.set('enrichedVars', enriched, 'file');
// met à jour propSelected
flow.set('propSelected', prop);

msg.info = `✅ Valeurs sauvegardées pour ${prop.nomP}`;
return { payload: null, info: msg.info };
